	// drop and recreate them. CASCADE handles any FK deps from other tables.
	const coreTablesOk = await (async () => {
		const res = await client.query(`
			SELECT column_name FROM information_schema.columns
			WHERE table_schema = current_schema()
			  AND table_name = 'accounts'
			  AND column_name = 'doc'
		`);
		return res.rows.length > 0;
	})();

	if (!coreTablesOk) {
		await client.query(`DROP TABLE IF EXISTS accounts CASCADE`);
		await client.query(`DROP TABLE IF EXISTS orders CASCADE`);
		await client.query(`DROP TABLE IF EXISTS invoices CASCADE`);
	}

	await client.query(`
		CREATE TABLE IF NOT EXISTS accounts (
			account_id TEXT PRIMARY KEY,
			doc JSONB
		)
	`);
	await client.query(`
		CREATE TABLE IF NOT EXISTS orders (
			order_id TEXT PRIMARY KEY,
			account_id TEXT,
			doc JSONB
		)
	`);
	await client.query(`
		CREATE TABLE IF NOT EXISTS invoices (
			invoice_id TEXT PRIMARY KEY,
			account_id TEXT,
			doc JSONB
		)
	`);

	const { generatePostgresSchema } = await import("../scripts/enterprise-schema-gen.mjs");
	const gen = generatePostgresSchema();
	await gen.ensureSchema(client);
	await client.query(`
